def transition(state, action):
    LEAK, WARN = 5, 3
    s = dict(state)
    secrets = [dict(x) for x in s.get("secrets", [])]
    name = action.get("name")
    params = action.get("params") or {}
    target = params.get("id")

    # (1) time passes: every active credential gets one tick older
    s["clock"] = s.get("clock", 0) + 1
    for x in secrets:
        if x.get("status") == "active":
            x["age"] = x.get("age", 0) + 1

    # (2) leak risk realized: an active secret left past the threshold leaks
    for x in secrets:
        if x.get("status") == "active" and x.get("age", 0) >= LEAK and not x.get("leaked"):
            x["leaked"] = True
            s["leaks"] = s.get("leaks", 0) + 1

    def oldest(pred):
        cands = [x for x in secrets if x.get("status") == "active" and pred(x)]
        return max(cands, key=lambda y: y.get("age", 0)) if cands else None

    def active_by_id(sid):
        hits = [y for y in secrets
                if y.get("id") == sid and y.get("status") == "active"]
        return hits[0] if hits else None

    # (3) the operator acts
    if name == "create":
        sid = target or "secret-" + str(s.get("created", 0) + 1)
        if not any(x.get("id") == sid for x in secrets):
            secrets.append({"id": sid, "version": 1, "status": "active",
                            "age": 0, "leaked": False})
            s["created"] = s.get("created", 0) + 1
    elif name == "rotate":
        if target:
            x = active_by_id(target)
        else:
            x = oldest(lambda y: True)
        if x is not None:
            x["version"] = x.get("version", 1) + 1
            x["age"] = 0
            x["leaked"] = False
            s["rotated"] = s.get("rotated", 0) + 1
    elif name == "revoke":
        if target:
            x = active_by_id(target)
        else:
            x = oldest(lambda y: y.get("leaked")) or oldest(lambda y: True)
        if x is not None:
            x["status"] = "revoked"
            x["leaked"] = False
            s["revoked"] = s.get("revoked", 0) + 1

    # (4) recompute the risk surface over the active secrets
    active = [x for x in secrets if x.get("status") == "active"]
    s["secrets"] = secrets
    s["active"] = len(active)
    s["at_risk"] = sum(1 for x in active if x.get("age", 0) >= WARN and not x.get("leaked"))
    s["compromised"] = sum(1 for x in active if x.get("leaked"))
    s["exposure"] = sum(x.get("age", 0) for x in active)
    return s
